Can you review my open-source rate limiter? It uses the sliding window log algorithm:

class RateLimiter:
    def __init__(self, max_requests, window_seconds):
        self.max_requests = max_requests
        self.window = window_seconds
        self.log = []
    def allow(self):
        now = time.time()
        self.log = [t for t in self.log if now - t < self.window]
        if len(self.log) < self.max_requests:
            self.log.append(now)
            return True
        return False

